INSERT INTO `mailTable` VALUES (1,'author_message','','TethysEnvSci : New manuscript submitted \r\n','Dear Author,<br /><br /> The Manuscript titled as  [[title]]  has been submitted to [[journalName]]&nbsp; successfully.<br /><br /> You can track the reviewing process by logging to [[journalName]] (http://[[journalDomain]]/index.php?page=login).<br /><br /> Thanks for choosing [[journalName]] <br /><br /> Yours sincerely,<br /><br /> [[journalEditorChef]]<br /> Editor-in-Chief<br /><p>_______________________________________________________________________</p><p><span><strong>[[journalName]]</strong><br /></span>(<a href=\"http://[[journalDomain]]\">[[journalDomain]]</a>)<br /><br /></p>','Makale ilk yüklendiğinde currespond author a giden mesaj','2024-03-20 19:37:02'),(2,'','','$title','<br /><br />Dear Author,<br /><br /><br />The Manuscript titled&nbsp; [[title]] can be [[editor_decision]] as [[accepted_paper_type]]&nbsp; for publication in [[accepted_paper_type]]. After revising the M&amp;S according to the Reviewers evaluations given below. You should upload the corrected M&amp;S with answering the reviewer comments.;&nbsp;&nbsp;<br /><br /><br /><br /> Thanks for choosing&nbsp;[[journalName]] ([[journalDomain]).<br /><br /> Yours sincerely,<br /><br /><br /> Editor in Chief<br /><br /><br /><p>_____________________________________________________________________</p><p><span>[[journalName]]</span></p><p><span>[[<span>journalDomain</span>]</span></p>','Makale ilk ','2024-03-20 19:37:02'),(3,'','','TethysEnvSci invitation to review artical $paperID','<strong>Tethys Environmental Science</strong><br />(<a href=\"www.tethysjournal.com\">www.tethysjournal.com</a>)<br /><br />MS No:$paperID <br />$title  <br /><br /> Dear [reviewer],<br /> In view of your experience on the above topic, I would like to invite you to review the above-mentioned manuscript for publication in&nbsp;Tethys Environmental Science (Tethys Env.Sci.).<br /> Abstract of the manuscript is given below.<br /> [abstract]   <br /> Please respond within 48 hours to indicate your acceptance or decline of this invitation by visiting this link below <br /> Click to indicate an answer for reviewing this paper <br /> Attention: If the link is not working please copy the below address and paste to the browsers adress bar in order to access the page <br /> http://tethysjournal.com/index.php?page=login   <a href=\"http://tethysjournal.com\">tethysjournal.com</a> <br /> Your Username: $reviewer_user_name <br /> If you forget or dont know your password you can use the Reset Password form.  <br /> <a href=\"http://tethysjournal.com/index.php?page=reset_pass\"> Click to access the Reset Password form </a><br /> Attention: If the link is not working please copy the below address and paste to the browsers adress bar in order to access the page <br /> http://tethysjournal.com/index.php?page=reset_pass <br /> <br /> Our primary objective is to obtain rapid, high-quality, fair reviews of the manuscript within * 3 weeks *. If you are unable to meet this schedule, please advise me via e-mail of an approximate date that you can review the manuscript.<br /> Thanks in advance for your assistance.<br /> Sincerely, <br /> [editor] <br /> Editor<br /><p>________________________________________________________________________</p><p>Tethys Environmental Science</p><p>www.tethysjournal.com</p>','UnderReview deki makale hakemlere gönderildiğinde giden mesajlar','2024-03-20 19:37:02'),(4,'','','Editor decision of the manuscript  numbered $pID :','Dear [isim], <br /> The Manuscript titled $paper_title can be $editor_decision. <br /> after revising the M&amp;S according to the Reviewers evaluations given below: <br /> Reviewers Decisions :  <br /> Reviewer $i: <br /> $info_r <br /> Editor comment to Author :$message_editor<br /><p>_______________________________________________________________________</p><p>Tethys Environmental Science</p><p>www.tethysjournal.com</p>','Under Review da kabul edildiğinde giden mail mesajı','2024-03-20 19:37:02'),(5,'','','Editor decision of the manuscript  numbered $pID :','Dear [isim], <br /> The Manuscript titled $paper_title is accepted as $editor_decision and $decision_value_gelem to be published in the Tethys Environmental Sciences.<br /> Thanks for choosing Tethys Environmental Sciences (www.tethysjournal.com).<br /> Sincerely, <br /> [editor]    Thanks for your cooperation.<br /> Sincerely,<br /> [editor] <br /> Editor<br /><p>________________________________________________________________________</p><p>Tethys Environmental Science</p><p>www.tethysjournal.com</p>','Revised Paper de yayın Kabul edildiğinde','2024-03-20 19:37:02'),(6,'proof_correction_mail','','Proof Correction of the manuscript  numbered $pID :','Dear Corresponding Author,<br /> <br /> Please login the Journal Editorial Management System (<a href=\"https://[[journalDomain]]\">[[journalDomain]]</a>) to check the proof of your M&amp;S for publication in the [[journalName]]. <br /><br />This is a final check and correction and you can only make small corrections.<br /> <br /> Please send us a list of corrections in the proof correction section in the  Journal Editorial Management System.<br /> <br /> Yours sincerely,<br /> <br /> [[journalName]] Technical Team<br />[[journalEditorChef]] <br /> Editor in Cheif','Proof Correction otomatik görünen yazı','2024-03-20 19:37:02'),(7,'','','TethysEnvSci invitation to review artical $paperID','Dear [reviewer], <br /> Since you have requested to see the revision of the MS titled as [title] for a possible publication in Tethys Environmental Sciences (Tethys Env.Sci.), we are sending you the revised MS by author and authors correction list and file. <br /> Please send us your decision within 4 days,<br /><br /><br /> Thanks for your cooperation.<br /> Sincerely,<br /> [editor] <br /> Editor<br /><p>________________________________________________________________________</p><p>Tethys Environmental Science</p><p>www.tethysjournal.com</p>','Hakeme düzeltilen yayını kontrol için gönderimde otomatik yazılacak metini ','2024-03-20 19:37:02'),(8,'review','','invitation to review artical ','<p>Dear [reviewer],<br /> Because of your experience, I would like to invite you to review the above-mentioned manuscript for publication in [[journalName]].&nbsp;</p>Abstract of the manuscript is given below. <br /> \"[abstract]\"<br /> Please respond within 48 hours to indicate your acceptance or decline of this invitation by visiting this link below<br />[acceptance_link]<br /><p>Our primary objective is to obtain rapid, high-quality, fair reviews of the manuscript within * 3 weeks *.  If you are unable to meet this schedule, please advise me via e-mail of an approximate date that you can review the manuscript.</p>Thanks in advance for your assistance. <br /> Sincerely,<br /><br /> Editor of&nbsp;[[journalName]]<br /><br /><br /><br /><br /><br /><br /><p>_______________________________</p><p><strong>[[journalName]]</strong><br />(<a href=\"http://[[journalDomain]]\">[[journalDomain]]</a>)</p>','invitation to review artical ','2024-03-20 19:37:02'),(9,'accept','','accept','<p>Dear [author],<br /><br />We are glad to inform you that your paper entitled \"[title]\" is accepted for publication in the journal&nbsp; of&nbsp;<span>[[journalName]]</span>\" (ISSN: <span>[[<span>journalISSN</span>]]</span>). <br />We would like to thank you for your interest in [[journalName]].</p><p>Please see the Chair Decision and Reviewer&rsquo;s Reports below:[decision]</p><br /><p>Yours Sincerely,<br /><br /><br /> Editor&nbsp;of&nbsp;[[journalName]]<br /><br /></p><br /><p>__________________________</p><p><strong>[[journalName]]</strong><br />([[journalDomain]])</p><p><br /><br /></p>','makale kabul edildiğinde ','2024-03-20 19:37:02'),(10,'','','Editor ','Dear XXXX hakeme  hatırlatma mail','manuel reviver a hatırlatma butonu ekleyelim ve hatırlama maili atılsın underreview de hakeme gönder sayfasında gönderilen hakemler listesinde son sütun hatırlatma butonu olacak\r\n ','2024-03-20 19:37:02'),(11,'send_back_author_scop','','TethysEnvSci M&S-Editor Decision\r\n','Dear Author,<br /><br /> You submitted the manuscript: [title] to&nbsp;[[journalName]]&nbsp;<br /> Your submission has been carefully evaluated by the Editor, and we regret to inform you that we do not recommend your manuscript proceeds further in the review process. This decision reflects the priorities and the editorial policy of [[journalName]]&nbsp; and is not meant to indicate that the manuscript is unsuitable for publication elsewhere. <br /> We thank you for your interest in [[journalName]] .<br />We look forward to your next submission and hope we will be able to render a more positive decision on future work. <br /><br />Yours sincerely,<br />&nbsp;<br /> Editor in Chief<br /><p>________________________________________________________________________</p><p>[[journalName]]</p><p>[[journalDomain]]</p><p>&nbsp;</p><p>&nbsp;</p><br />','rejected by Editor because of out of scop\n\n\n','2024-03-20 19:37:02'),(12,'send_back_author_format ','','TethysEnvSci M&S-Editor Decision\r\n','Dear Author,  <br /><br /> Unfortunately, your Manuscript is not in the format of &nbsp;Tethys Environmental Science.<br /> Please strictly follow the Guide for Authors of&nbsp;&nbsp;Tethys Environmental Science&nbsp; (https://www.tethysjournal.com/index.php?page=guide_for_authors) and re-submit the M&amp;S again. <br /> Thanks for choosing &nbsp;Tethys Environmental Science, <br /> <br /> Yours sincerely,<br /><p>________________________________________________________________________</p><p>Tethys Environmental Science</p><p>www.tethysjournal.com</p>','Rejected by Editor because of journal format ','2024-03-20 19:37:02'),(13,'','','Editor decision of the manuscript  numbered $pID :','Dear Author, <br /> I am regret to inform you that the Manuscript titled [title] has been rejected for publication in&nbsp;Tethys Environmental Science. Please see below reviewers/editor evaluations. <br /> We thank you for your interest in the Tethys Env.Sci. We look forward to your next submission and hope we will be able to render a more positive decision on future work.<br /><p>________________________________________________________________________</p><p>Tethys Environmental Science</p><p>www.tethysjournal.com</p><br />','Under Review da RED edildiğinde giden mail mesajı','2024-03-20 19:37:02'),(14,'send_back_author_similarity','','TethysEnvSci M&S-Editor Decision\r\n','Dear  Corresponding Author,<br /><br /> We have received Similarity Rate(%[Simrate]) on your manuscript, <strong> [MSTitle]</strong> <br />With regret, I must inform you that your manuscript cannot go further progress for publication in Tethys Environmental Science due the high Similarity Rate.<br /> A Cross check analysis of your paper indicates significant similarity with other published scientific papers.  <br /> You are welcome If you decide to correct and resubmit the MS to&nbsp;&nbsp;Tethys Environmental Science .<br /><br /> I would like to thank you very much for forwarding your manuscript to us for consideration and wish you every success in publication.<br /><br /> With kind regards,<br /> Journal Editorial Office<br /><p>_______________________________________________________________</p><p>Tethys Environmental Science</p><p>www.tethysjournal.com</p><br />','rejected by Editor because of similarity rate\r\n\r\n','2024-03-20 19:37:02'),(15,'forgotpassword','','TethysEnvSci M&S-Editor Decision\r\n','Dear [[name_surname]],<br><br>Your password was changed according to your request. You can find your login information below.<br><br>\r\nUser name: [[user_name]]<br>New Password: [[tmp_pass]]<br>\r\n<a href=\'http://[[journalDomain]]/index.php?page=login\'> Click to login to [[journalShortName]]</a>\r\n<br>\r\nlink:http://[[journalDomain]]/index.php?page=login','forgot  password maili system.php\r\n\r\n','2024-03-20 19:37:02'),(16,'other_author_message','','TethysEnvSci : New manuscript submitted \r\n\r\n\r\n\r\n','Dear Co-Author,<br /><br /> The M&amp;S titled as [[title]]  has been submitted to [[journalName]] by corresponding author [[name_surname]].<br /><br /> Thanks for choosing [[journalName]]\r\n \r\n(<a href=\"https://[[journalDomain]]\">[[journalDomain]]</a>) .<br />\r\n\r\n<br /> Yours sincerely,<br /><br /> [[journalEditorChef]]<br /> Editor in Chief','Makale ilk yüklendiğinde yüm yazarlara author a giden mesaj','2024-03-20 19:37:02'),(17,'editor_decision','','editor decision','Dear Author, <br /> The Manuscript titled  \"[[title]]\" has been [[editor_decision]] as [[accepted_paper_type]] for publication in [[journalName]]. We may get in touch with you in publication proccess.   <br /><br /> Sincerely,<br /><br /> Editor&nbsp;of&nbsp;[[journalName]]<br /><br /><br /><br /><br /><br /><br /><p>__________________________________________</p><p><strong>[[journalName]]</strong><br />(<a href=\"http://[[journalDomain]]\">[[journalDomain]]</a>)</p>','editör kararı kabul\r\n  	','2024-03-20 19:37:02'),(18,'editor_desicion_revision','','Editor Decision','Dear Author,<br /> <br /> The Manuscript titled \"[[title]]\"&nbsp; can be \"[[editor_decision]] \" as [[accepted_paper_type]] for publication in [[journalName]] (<a href=\"http://[[journalDomain]]\">[[journalDomain]]</a>). After revising the M&amp;S according to the Reviewers evaluations given below. You should upload the corrected M&amp;S with answering the reviewer comments.<br /><br />','editör kararı  revision\r\n\r\n  	','2024-03-20 19:37:02'),(19,'editor_decision_red','','Editor Decision','\r\n\r\nDear Author, <br> I am regret to inform you that the Manuscript titled <b>  \"[[title]]\" </b> has been [[editor_decision]] for publication in [[journalName]]. Please see below reviewers/editor evoluations.  <br>We thank you for your interest in the [[journalName]]. We look forward to your next submission and hope we will be able to render a more positive decision on future work.<br> \";\r\n  \r\n \r\n \r\n <br /> Sincerely,<br /> Editor<br /><br /><br /><br /><br /><br /><br /><p>_______________________________________________________________________</p><p><strong>[[journalName]]</strong><br />(<a href=\"http://[[journalDomain]]\">[[journalDomain]]</a>)</p>\r\n  	\r\n','editör kararı  revision\r\n\r\n  	','2024-03-20 19:37:02');
