INSERT INTO `mail_text` VALUES (1,'review','<p>Dear [reviewer],<br />  \r\nBecause of your experience, I would like to invite you to review the above-mentioned manuscript for publication in Tethys environmental Science (TethysEvnSci).&nbsp;</p>\r\nAbstract of the manuscript is given below.\r\n<br /> \"[abstract]\"<br/>\r\nPlease respond within 48 hours to indicate your acceptance or decline of this invitation by visiting this link below</br>[acceptance_link]</br>\r\n<p>Our primary objective is to obtain rapid, high-quality, fair reviews of the manuscript within * 3 weeks *.  If you are unable to meet this schedule, please advise me via e-mail of an approximate date that you can review the manuscript.</p>  \r\nThanks in advance for your assistance. <br />\r\nSincerely,<br />\r\n[editor]</br>\r\nEditor\r\n'),(2,'accept','<p>Dear [author],<br />We are glad to inform you that your paper entitled \"[title]\" is accepted for publication in the research journal \"Tethys Environmental Science\" (ISSN: 2458-8989). We would like to thank you for your interest.</p>\r\n<p>Please see the Chair Decision and Reviewer&rsquo;s Reports below:[decision]</p> <br />\r\n<p>Yours Sincerely,<br /> Prof. Cemal Turan<br /> Tethys Environmental Science <br /> Editor-in-Chief </p>\r\n');
