INSERT INTO `send_back_author` VALUES (1,95,'Yakup Kutlu','Dear Author,  <br /><br /> Unfortunately, your Manuscript is not in the format of  Tethys Environmental Science.<br /> Please strictly follow the Guide for Authors of  Tethys Environmental Science  (https://www.tethysjournal.com/index.php?page=guide_for_authors) and re-submit the M&S again. <br /> Thanks for choosing  Tethys Environmental Science, <br /> <br /> Yours sincerely,<br /><p>________________________________________________________________________</p><p>Tethys Environmental Science</p><p>www.tethysjournal.com</p></br></br>Yakup Kutlu</br>Editor','2024-08-03'),(2,96,'Yakup Kutlu','Dear Author,<br /><br /> You submitted the manuscript: test quis id eu nemo m to Tethys Environmental Science <br /> Your submission has been carefully evaluated by the Editor, and we regret to inform you that we do not recommend your manuscript proceeds further in the review process. This decision reflects the priorities and the editorial policy of Tethys Environmental Science  and is not meant to indicate that the manuscript is unsuitable for publication elsewhere. <br /> We thank you for your interest in Tethys Environmental Science .<br />We look forward to your next submission and hope we will be able to render a more positive decision on future work. <br /><br />Yours sincerely,<br /> <br /> Editor in Chief<br /><p>________________________________________________________________________</p><p>Tethys Environmental Science</p><p>www.tethysjournal.com</p><p> </p><p> </p><br /></br></br>Yakup Kutlu</br>Editor','2024-08-03'),(3,97,'Yakup Kutlu','Dear  Corresponding Author,<br /><br /> We have received Similarity Rate(%0) on your manuscript, <strong> test Laborum Nam aut amet</strong> <br />With regret, I must inform you that your manuscript cannot go further progress for publication in Tethys Environmental Science due the high Similarity Rate.<br /> A Cross check analysis of your paper indicates significant similarity with other published scientific papers.  <br /> You are welcome If you decide to correct and resubmit the MS to  Tethys Environmental Science .<br /><br /> I would like to thank you very much for forwarding your manuscript to us for consideration and wish you every success in publication.<br /><br /> With kind regards,<br /> Journal Editorial Office<br /><p>_______________________________________________________________</p><p>Tethys Environmental Science</p><p>www.tethysjournal.com</p><br /></br></br>Yakup Kutlu</br>Editor','2024-08-03');
/*!40000 ALTER TABLE `send_back_author` ENABLE KEYS */;
UNLOCK TABLES;

