INSERT INTO `static_content` VALUES (1,'Home','home','<h6 style=\"text-align: justify;\"><p><strong><br />Tethys Environmental Science</strong>&nbsp;(e-ISSN: 3023-7343) is a&nbsp;multidisciplinary peer-reviewed electronic journal that provides publication of research articles in topical areas of&nbsp;Environmental Science.&nbsp;<br /><br />Tethys Environmantal Science&nbsp;<strong>(http://www.tethysjournal.com)&nbsp;</strong>is published <strong>trimesterly </strong>and&nbsp;<strong>does not charge any processing and publication fee.</strong> The goal of this journal is to provide a platform for researchers, students, professionals and academicians all&nbsp; over the world to combine, promote, share, and discuss new ideas, issues,&nbsp;developments and its application in different areas of Environmental Science.<br /> <strong><br /></strong><strong>Tethys Environmental Science</strong>&nbsp;welcomes the submission of manuscripts that meet the general criteria of significance and scientific excellence, and will publish:</p><ul><li>Original research articles, case studies, reviews and essays&nbsp;on the determined topics at the scope.&nbsp;</li></ul><p style=\"text-align: justify;\"><strong>Tethys Environmental Science</strong><span>&nbsp;</span>is fully committed to the Open Access Initiative and provides&nbsp;free access to all articles as soon as they are published. Articals&nbsp; should be written in English language in a Microsoft word document and should have proper terminologies. Our objective is to inform authors of the decision on their artical within four to eight weeks of submission, depending on reviewer avaibility. Following acceptance, the artical will normally be published in the next issue.</p><p style=\"text-align: justify;\">Open access gives a worldwide audience larger than that of any subscription-based journal and thus increases the visibility and impact of published works. It also enhances indexing, retrieval power and eliminates the need for permissions to reproduce and distribute content.&nbsp;</p><p>The advantages to you of publishing in Tethys Environmental Science;</p><ul><li>Full open access: everyone can read your article when it is published</li><li>Fair peer review from two or more expert peer reviewers</li><li>Frequent updates on your paper&rsquo;s status</li><li>Friendly responsive staff</li></ul></h6><h6>We welcome all your submissions.<br /><br />Warm regards,</h6><h6>Editorial Board</h6><br />---------------------------------------------------------<br />THE PUBLISHER is CEMAL TURAN.',1,'2024-03-20 19:38:04'),(2,'Editorial Board','editorial_board','<!-- Category Start --><div class=\"container-xxl py-5\"><div class=\"container\"><h1 class=\"text-center mb-5 wow fadeInUp\">Editor-in-Chief</h1><div class=\"row g-4 justify-content-center\"><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\">Dr. Cemal Turan</h6><p class=\"mb-0\">Iskenderun Technical University</p><p class=\"mb-0\">e-mail: cemal.turan@iste.edu.tr</p></a></div></div></div></div><!-- Category End --> <!-- Category Start --><div class=\"container-xxl py-5\"><div class=\"container\"><h1 class=\"text-center mb-5 wow fadeInUp\">Managing Editor</h1><div class=\"row g-4 justify-content-center\"><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\">Dr. Yakup Kutlu</h6><p class=\"mb-0\">Iskenderun Technical University</p><p class=\"mb-0\">e-mail: yakup.kutlu@iste.edu.tr</p></a></div></div></div></div><!-- Category End --> <!-- Category Start --><div class=\"container-xxl py-5\"><div class=\"container\"><h1 class=\"text-center mb-5 wow fadeInUp\">Editor</h1><div class=\"row g-4 justify-content-center\"><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\">Dr. Ali Uyan</h6><p class=\"mb-0\">Iskenderun Technical University</p><p class=\"mb-0\">e-mail: ali.uyan@yahoo.com</p></a></div></div></div></div><!-- Category End --> <!-- Category Start --><div class=\"container-xxl py-5\"><div class=\"container\"><h2 class=\"text-center mb-5 wow fadeInUp\">Editor Board</h2></div></div><!-- Category End --> <!-- Category Start --><div class=\"container-xxl py-5\"><div class=\"container\"><div class=\"row g-4 justify-content-center\"><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\">Dr. Alen Soldo</h6><p class=\"mb-0\">University of Split</p><p class=\"mb-0\">e-mail:soldo@unist.hr</p><p class=\"mb-0\">Croatia</p></a></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\">Dr. Antonia Khanaychenko</h6><p class=\"mb-0\">Institute of Marine Biological Research, Sevastopol <br /> e-mail: a.khanaychenko@gmail.com<br /> Russia</p></a></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\">Dr. Athanasios Exadactylos</h6><p class=\"mb-0\">University of Thessaly<br /> e-mail: exadact@uth.gr<br /> Greece</p></a></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\">Dr. Azza El-Ganainy</h6><p class=\"mb-0\">Egypt National Institute of Oceanography and Fisheries<br /> e-mail: azzaelgan@yahoo.com<br /> Egypt</p></a></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\">Dr. Petya Ivanova</h6><p class=\"mb-0\">Institute of Oceanology<br /> Bulgarian Academy of Science<br /> e-mail:pavl_petya@yahoo.com<br /> Bulgaria</p></a></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\">Dr. Darius Andriukaitis</h6><p class=\"mb-0\">Kaunas University of Technology<br /> e-mail:darius.andriukaitis@ktu.lt<br /> Lithuania</p></a></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\"><br />Dr. Lovrenc Lipej</h6><p class=\"mb-0\">Marine Biology Station<br /> e-mail: Lovrenc.Lipej@nib.si<br /> Slovenia</p></a></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\">Dr. Violin Raykov</h6><p class=\"mb-0\">Institute of Oceanology<br /> Bulgarian Academy of Science<br /> e-mail: vio_raykov@abv.bg<br /> Bulgaria</p></a></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\"><a class=\"cat-item border rounded-pill p-4 text-center text-white \"><h6 class=\"text-white mb-3\">Dr. Quratulan Ahmed</h6><p class=\"mb-0\">University of Karachi<br /> e-mail: quratulanahmed_ku@yahoo.com<br /> Pakistan</p></a></div></div></div></div><!-- Category End --><p>&nbsp;</p><p>&nbsp;</p><p style=\"text-align: center;\"><span style=\"color: #0000ff; font-size: medium;\"><strong>Publication Ethics Consultant</strong></span></p><p style=\"text-align: center;\"><strong><a href=\"https://www.dogavebilim.com/?lang=en\">Nature   and Science Society</a></strong><strong>&nbsp;</strong></p>',1,'2024-03-20 19:38:04'),(3,'Award','award','<br /><strong><span>Tethys Environmental Sciences</span>&nbsp;will give an <span style=\"color: #ff0000;\">Award to the Best Artical</span> published in <strong>Tethys Env. Sci.&nbsp;</strong>for each year.&nbsp;</strong><br /><strong><br /><br />The best artical will be chosen by Editorial Board Members.&nbsp;</strong>',1,'2024-03-20 19:38:04'),(4,'Guide For Authors','guide_for_authors','<pre><br /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\"><h2 style=\"color: #ffffff;\">CONTENT</h2> </span></td></tr></tbody></table></pre><ul><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#title\">Title</a> </span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#abstract\">Abstract</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#keywords\">Keywords</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#main\">Main Text</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#main\">Introduction</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#main\">Materials and Methods</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#main\">Results</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#main\">Discussion</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#cite\">Citing in Text</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#footnote\">Abbreviations</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#footnote\">Footnotes</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#acknowledgments\">Acknowledgments</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#data\">Funding Source</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#data\">Author Contributions</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#data\">Data Availability Statement</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#conflicts\">Conflicts of Interest/Competing Interests</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#ethical\">Compliance with Ethical Standards</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#references\">References</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#download\">Copyright Form</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#download\">Suggesting Reviewers</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#download\">Reviewing Process&nbsp;</a></span></li><li><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"#download\">Publication Fee</a></span></li></ul><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">&nbsp;</span></td></tr></tbody></table><p style=\"text-align: justify;\"> <br />Thank you for your interest in the&nbsp;Tethys Environmantal Science.  You can submit your manuscript or track your submission via  <a href=\"../index.php?page=login\">Editorial Manager for online submission and manuscript tracking</a>.&nbsp;We look forward to handling your submission.  <br />In order to allow swift consideration of your work,&nbsp;<span>Tethys Environmantal Science&nbsp;</span> has relaxed some aspects of manuscript formatting until a manuscript is resubmitted following review and provisional acceptance for publication.   Therefore, please carefully follow these instructions to avoid unnecessary delay and possible rejection of your paper.<br />The aim and scope of <span>Tethys Environmantal Science </span>is to publish exciting, high quality science that addresses fundamental questions in Environmantal Science.   The Author declares that the manuscript is original and has not been published elsewhere in any form, that it has not been submitted to any journal/proceedings and   that it will not be submitted to any other journal/proceedings.  To verify originality, your article may be checked by the originality detection service&nbsp;  <a href=\"http://www.ithenticate.com/products/crossref-similarity-check\"><strong>Crossref Similarity Check</strong>.</a> In the <strong>iThenticate and Turnitin Similarity Reports</strong>, a maximum overall similarity score of an M&amp;S must be less than <strong>20%</strong> without References.   The Author is responsible for the research and results described in the paper&nbsp;If it is accepted for publication in the  <span>Tethys Environmantal Science</span>.&nbsp;If the article is a joint work of several authors (co-authors),   the Author who submits the article declares that any person named as author (co-author) of the Article is aware of the requirements of this agreement and has agreed  to being so named.&nbsp;The Author warrants that the article does not infringe upon any copyright,  contains no libelous or otherwise unlawful statements and does not otherwise infringe on the rights of others. The authors retain the copyright and grant the publisher a non-exclusive license to publish the article under the Creative Commons Attribution 4.0 International License (CC BY 4.0) which is contained in page of \r\n<a href=\"https://tethysjournal.com/index.php?page=copyright_and_licensing\">Copyright and Licensing of journal.</a>\r\n\r\n\r\n\r\n   <br />Authors must follow the national and international ethical standards for all kind of experiments   (both on human beings, and on animals).</p><p><strong> Preparation of Manuscript</strong></p><p>Manuscripts must be submitted in electronic version only, as well as the original figures and tables.</p><p style=\"text-align: justify;\">Authors are recommended to use their ORCID ID when submitting an article for consideration or acquire an ORCID ID via the submission process.<br /> <br /><span style=\"text-align: justify;\">The text of the manuscript should be single-spaced throughout and with 2,5 mm left and right and 1,25 top and bottom margins, including References,   Tables and Figures on A4 paper format using a standard font (e.g. MS Word, Times New Roman, 12 punts).</span> <span style=\"text-align: justify;\"> &nbsp;In order to facilitate the review process, line numbers should be inserted throughout the manuscript.<br /><br /> During the submission, authors must upload a &ldquo;<strong>Graphical Abtract</strong>&rdquo; or &ldquo;<strong>Visual Abstract</strong>&rdquo; representing the body of the article.   This is a single, concise, pictorial and visual summary of the the article.   The graphical abstract should be designed to give readers an immediate understanding of the take-home message of the article.  The format of the graphical abstract must be one page of &ldquo;jpg&rdquo; or &ldquo;Power Point&rdquo; file.&nbsp;</span></p><p><strong>The structure of the manuscript </strong></p><strong>1.&nbsp;</strong>Title&nbsp;<br /><strong>2.</strong> Abstract<br /><strong>3.</strong> Keywords<br /><strong>4. </strong>Introduction<br /><strong>5. </strong>Materials and Methods<br /><strong>6. </strong>Results<br /><strong>7. </strong>Discussion<br /><strong>8.</strong> Acknowledgments<br /><strong>9. </strong>Funding Source<br /><strong>10.</strong> Author Contributions<br /><strong>11. </strong>Data Availability Statement<br /><strong>12.</strong>&nbsp;Conflicts/Competing of Interests<br /><strong>13.</strong> Compliance with Ethical      Standards<br /><strong>14. </strong>References<p>&nbsp;</p><a name=\"title\"> </a><p><strong>1. Title</strong></p><p><span style=\"text-align: justify;\">A concise and informative title should be given, and the title should be in sentence format. The title should be in lower case form.&nbsp;</span><span style=\"text-align: justify;\">Below the title; authors full name, authors affiliations, and mark \"*\" by&nbsp;corresponding author.&nbsp;</span><span style=\"text-align: justify;\">The e-mail address of the corresponding author </span><span style=\"text-align: justify;\">author must be placed.&nbsp;</span><span style=\"text-align: justify;\">The address of every author&rsquo;s primary affiliation (university, research institute, etc.) must be given in full. Ideally, no more than one address per author should appear.&nbsp;</span></p><a name=\"abstract\"> </a><p><strong>2. Abstract </strong></p><p style=\"text-align: justify;\">The abstract should not exceed 250 words in research papers, the abstract should not contain any undefined abbreviations or unspecified references.</p><a name=\"keywords\"> </a><p><strong>3. Keywords</strong></p><p style=\"text-align: justify;\">Please provide 3 to 5 keywords which can be used for indexing purposes.</p><a name=\"main\"> </a><p><strong>Main Text</strong></p><p style=\"text-align: justify;\">The main text comprises <span style=\"font-size: small;\"><strong>4. Introduction</strong>, <strong>5.&nbsp;Materials and Methods</strong>, <strong>6.&nbsp;Results</strong>, <strong>7.&nbsp;Discussion </strong></span>episodes. Items 6<sup>th</sup> and 7<sup>th</sup> can be done together as \"<span><strong>Result and Discussion\"</strong>, then, there is no need for \"<strong>Discussion</strong>\" again.&nbsp;</span></p><ul><li>For submission in MS-Word format, <strong>Table and Figures must be embedded within the tex</strong>t using Arabic numbers, e.g. Figure 1, Figure 2, Table 1, Table 2 etc., in order of appearance. </li><li>One line space must be given before and after Tables and Figures in the text. </li><li>The preferred position of tables and figures in the text should be indicated in the left-hand margin.&nbsp;</li><li>Figure captions and table headings should be sufficient to explain the figure or table without needing to refer to the text. </li><li>Figures and Tables not cited in the text should not be presented. </li><li>Photographs (only in JPEG format) should have a resolution of 600 to 1200 dpi (line drawings) in relation to the reproduction size. </li><li>Only high-contrast photographic material is suitable for reproduction. </li><li>Figures and Tables must be limited to an essential minimum, at most 9 for each.&nbsp;&nbsp;</li><li>There should not be a line inside the table, but there should be line at the top and bottom side of the Tables.&nbsp;</li><li>Figure captions should be in Times New Roman font and 12 point font size. </li><li>There should not be a line at main outline of the Figure.&nbsp;</li><li>Original contributions should not exceed 15 manuscript pages, all single-spaced. </li> <li>At the end of Discussion, a Conclusion should be included.&nbsp; </li><li>The Authors should include a statement on the welfare of animals in the Materials and Methods as&nbsp;<strong>Compliance with Ethical Standards</strong> if the research involved animals when submitting a paper. </li><li>The author will be held responsible for false statements or failure to fulfill the above-mentioned statement.</li></ul><a name=\"cite\"> </a><p><strong>Citing in text</strong></p><p>Articles cited in the text should be referred to as follows: By the surname of the author(s) with year of publication in parenthesis. Example: Charvalho and Turan (2018).</p><p>If both are in parenthesis, no punctuation separates the name(s) of the author and the year of publication. Example: (Carvalho&nbsp;and&nbsp;Turan, 2017).</p><p>If there are more than two authors only the senior author&rsquo;s name is given. Example: (Carvalho et al., 2017).</p><a name=\"footnote\"> </a><p><strong>Abbreviations</strong></p><p style=\"text-align: justify;\">Abbreviations should be defined at first mention and used consistently thereafter.</p><a name=\"footnote\"> </a><p><strong>Footnotes</strong></p><p style=\"text-align: justify;\">Footnotes can be used to give additional information, which may include the citation of a reference included in the reference list.</p><p style=\"text-align: justify;\">Footnotes to the text are numbered consecutively; those to tables should be indicated by superscript lower-case letters (or asterisks for significance values and other statistical data).</p><a name=\"acknowledgments\"> </a><p><strong>8. Acknowledgments</strong></p><p style=\"text-align: justify;\">Authors can thank any help obtained during the research and indicate funding with&nbsp;Grant number.</p><a name=\"data\"> </a><p><strong>9. Funding Source</strong></p><p style=\"text-align: justify;\">You are requested to identify who provided financial support for the conduct of the research and/or preparation of the article and to briefly describe the role of the sponsor(s). If the funding source(s) had no such involvement then this should be stated.</p><a name=\"data\"> </a><p><strong>10. Author Contributions</strong></p><p style=\"text-align: justify;\">For transparency, we encourage authors to designate with an author statement outlining their individual contributions to the paper.</p><a name=\"data\"> </a><p><strong>11. Data Availability Statement </strong> &lt; /p&gt;Authors should      provide a data availability statement with the submission. Followings are      few examples of such statements:</p><ul><li>The data that support the findings of this study are openly      available in [repository name] at [doi], reference number [reference      number].</li><li>The data supporting the findings of this study are available      within the article [and/or] its supplementary materials.</li><li>The data that support the findings of this study are available on      request from the corresponding author, [initials].</li><li>Data sharing is not applicable to this article as no new data were      created or analysed in this study.</li></ul><a name=\"conflicts\"> </a><p><strong>12. Conflicts of Interest</strong>/<strong>Competing Interests</strong></p><p class=\"Govde\">Any existing conflicts of interest/competing interest should be given here.</p><p class=\"Govde\">If no conflict/competing exists, the authors should state: The authors declare that they have no conflict of interest.<em>&nbsp;</em></p><a name=\"ethical\"> </a><p><strong>13. Compliance with Ethical Standards&nbsp;</strong></p>The studies &nbsp;involving humans and/or animals rights&nbsp; must&nbsp;have been approved by the appropriate institutional and/or national research ethics committee and performed in accordance with the ethical standards as laid down in the 1964 Declaration of Helsinki and its later amendments or comparable ethical standards.<strong>&nbsp;</strong>All applicable international, national, and/or institutional guidelines for the care and use of animals should have been followed.&nbsp;Therefore, additional declarations for articles that report the results of studies involving humans and/or animals are required.&nbsp;For this reason, during the submission, the authors are asked to include the following statements in a separate section entitled &ldquo;<strong>Compliance with Ethical Standards</strong>&rdquo; to declare whether the results of study involve humans and/or animals rights.<p>&nbsp;</p><p class=\"Govde\">If no, the authors declare that&nbsp;&nbsp;the results of study do not involve humans and/or animals rights.</p><p>If yes, the corresponding author should fill&nbsp;<strong><a href=\"journal_files/Ethical_Principles_and_Publication_Policy_TethysEnvSci.docx\">Statement for the Ethics Committee Approval Form</a>&nbsp;</strong>(given below) and submit it during M&amp;S submission.&nbsp;</p><p>The Editors reserve the right to reject manuscripts that do not comply with the above-mentioned guidelines. The author will be held responsible for false statements or failure to fulfill the above-mentioned guidelines.</p><a name=\"references\"> </a><p><strong>14. References</strong></p><p class=\"spaced\">References should be listed in alphabetical order according to the name of the first author.</p><p class=\"spaced\"><em><strong>Use the Following Examples for Arranging the References:</strong></em></p><p><strong>Journal</strong></p><p class=\"spaced\">Uyan, A., Turan, C., Doğdu, S., G&uuml;rlek, M., Yağlıoğlu, D., S&ouml;nmez, B. (2024). Genetic and Some Bio-Ecological Characteristics of Lessepsian Lizardfish Saurida lessepsianus from the Northeastern Mediterranean Sea. Tethys Environmental Sciences, 1(1), 1-16.</p><p class=\"spaced\">Vella, N., Vella, A., Mifsud, C. (2017). First scientific records of the invasive Red Swamp Crayfish,&nbsp;<em>Procambarus&nbsp;</em>clarkii (Girard, 1852) (Crustacea: Cambaridae) in Malta, a threat to fragile freshwater habitats.&nbsp;<em>Natural and Engeenering Sciences</em>, 2(2), 58-66.&nbsp;</p><p class=\"spaced\"><strong><em>Book</em><br /></strong></p><p><span>Nairn, A.E., Ricou, L.E., Vrielynck, B., Dercourt, J. (Eds.). (2013).&nbsp;</span>The Tethys Ocean<span>&nbsp;(Vol. 8). Springer Science &amp; Business Media.</span>&nbsp;</p><p>Avise, J.C. (2012). Molecular markers, natural history and evolution. Springer Science &amp; Business Media.<br /><br /><span>Turan, C. (2007). Atlas of marine bony fishes of Turkey.</span>&nbsp;Nobel Publishing House<span>.</span></p><p class=\"spaced\"><em><strong>Book Chapter</strong></em></p><p><span>Beisner, B.E., Thackeray, S.J. (2024).&nbsp;Ecology and Functioning of Zooplankton Communities. <em>In</em> Weltzels Limnology (pp. 587-620). Academic Press.<br /></span><br />Turan, C. (2015). Biogeography and Distribution of Mugilidae in the Mediterranean and the Black Sea, and North-East Atlantic. Biology, Ecology and Culture of Grey Mullets (Mugilidae). A Science Publishers Book. CRC Press, USA, 116-127.</p><p class=\"spaced\"><span>&nbsp;<br /></span><em><strong>Proceedings paper</strong></em></p><p class=\"spaced\">Ibrahım, S., El-Gnainy, A., Imam, N., Fadel, A., Abouzied, A. (2017). Effect of gamma rays on nutritive value and vibrio alginlyticus of pufferfish (<em>Lagocephalus sceleratus</em>) Fillets. In: Book of Abstract. &nbsp;International Symposium on Pufferfish, 13-14 October 2017, Bodrum, Turkey. p.13.</p><p><em><strong>Theses</strong></em></p><p>Yağlıoğlu, D. (2011). Colonization and genetic changes of Indo-Pacific origined species in the Mediterranean. Mustafa Kemal University, Institute of Science. Hatay, p 135.</p><p class=\"spaced\"><em><strong>Translation</strong></em><br /> Laplace, P. S. (1951).&nbsp;A philosophical essay on probabilities. (F. W. Truscott &amp; F. L. Emory, Trans.). New York, NY: Dover. (Original work published 1814).</p><p class=\"spaced\"><strong><em>Websites</em><br /> </strong>Froese, R., &amp; Pauly. D. (Eds). (2024). FishBase. World Wide Web electronic publication. www.fishbase.org, version (02/2024).</p><p class=\"spaced\"><em><strong>Organizations</strong></em></p><p class=\"spaced\">FAO. (2006). Global Forest Resources Assessment 2005, <em>FAO Forestry Paper </em>147. Available at: <a href=\"ftp://ftp.fao.org/docrep/fao/008/a0400e/\">ftp://ftp.fao.org/docrep/fao/008/a0400e</a> (28.05.12).&nbsp;</p><a name=\"download\"> </a><p><strong>Copyright Form</strong></p><p>After acceptance of the manuscript, the \"<strong><a href=\"journal_files/Copyright_Form_TethysEnvSci.docx\">Copyright Form</a>\"</strong>&nbsp; must be filled in completely and signed by the corresponding author on behalf of all authors, and attached with the revised M&amp;S.&nbsp;</p><p><strong>Suggesting reviewers</strong></p><p>During the M&amp;S submission in the Editorial Manager Sytem, corresponding author can submit names of potential reviewers with their affiliations and email addresses. However, Editor/<span>Editorial Board Members&nbsp;</span>may select one of the suggested reviewers or all reviewers other than the suggested reviewers from our own reviewer resources.</p><p><strong> Reviewing Process </strong></p>Editor-in-Chief/Editor/Editorial Board Members dealing with the manuscript may return any unreviewed manuscript that falls outside the journal&rsquo;s policy or scope.<p>&nbsp;</p><div>All manuscripts will be single-blind peer-reviewed by at least two external referees.</div><p><strong> Publication Fee </strong></p>Tethys Environmental Science does not require any processing and publication fee.&nbsp;<br /><br /><span style=\"font-size: small;\"><strong><strong>Forms&nbsp;</strong></strong></span><p>&nbsp;</p><ul style=\"list-style-type: circle;\"><li><strong><span style=\"font-size: medium;\"><span style=\"color: #ff0000;\"><span style=\"color: #ff0000; font-size: medium;\"> Download the Copyright Form :&nbsp;</span><span style=\"font-size: medium;\"> <a title=\"COPYRIGHT FORM\" href=\"journal_files/Copyright_Form_TethysEnvSci.docx\"> <span style=\"color: #0000ff;\">&nbsp;WORD DOWNLOAD</span></a></span></span></span></strong></li><li><strong style=\"font-size: 1.17em;\"><span style=\"font-size: medium;\"><a title=\"Statement for the Ethics Committee Approval Form\" href=\"journal_files/Statement_for_the_Ethics_Committee_Approval_TethysEnvSci.doc\"><span style=\"color: #ff0000;\"><strong>Statement for the Ethics Committee Approval Form  <span style=\"color: #0000ff;\">:</span></strong><span style=\"color: #0000ff;\">&nbsp;WORD DOWNLOAD</span></span></a></span></strong></li></ul>',1,'2024-03-20 19:38:04'),(5,'Archive','archive','<p style=\"text-align: justify;\"><span><strong><a class=\"accordion-toggle collapsed from-journal\"><br />Archiving Policy</a></strong><br /><br />To guarantee that all articals published in the&nbsp;<span>Tethys Environmental Science</span> are maintained and permanently accessible. All published articles are stored in the open repository Zenodo&nbsp;(https://zenodo.org)&nbsp;which serves as an international archival web site and at the same time permits LOCKSS to collect, preserve, and serve the content.<br /><br /></span></p><p style=\"text-align: justify;\"><span>Additionally, authors are encouraged to self-archive the final PDF version of their articles in open electronic archives with &nbsp;that conform to standards of Open Archives Initiative (</span><a href=\"https://www.openarchives.org/\" target=\"_blank\"><span>https://www.openarchives.org/</span></a><span>).&nbsp;Authors should provide a link from the deposited version to the URL of IUPress journal website.<br /><br /></span></p>',1,'2024-03-20 19:38:04'),(6,'INDEX','index','<br /><p><span>Tethys Environmental Science</span><span>&nbsp;i</span>s an international open access journal and&nbsp;make every effort to ensure the accuracy of all the information contained in our publications. Any opinions and views expressed in this publication are the opinions and views of the authors, and are not the views of or endorsed by&nbsp;Tethys Environmental Science&nbsp;. <strong>Tethys Env.Sci.&nbsp;</strong>does not charge any publication fee.<em><br /></em></p><p><br /> <!-- Category Start --></p><h5 class=\"text-center mb-5 wow fadeInUp\"><strong>Tethys Environmental Science&nbsp;<span>is indexed/tracked/covered by the following services:</span></strong></h5><strong> </strong><div class=\"container-xxl py-5\"><div class=\"container\"><div class=\"row g-4 justify-content-center\"><div class=\"col-lg-4 col-sm-6 wow fadeInUp\" style=\"visibility: visible; animation-name: fadeInUp;\"><img src=\"../images/openaccess_logo.png\" alt=\"openaccess\" width=\"200px\" /><p class=\"mb-0\">&nbsp;</p></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\" style=\"visibility: visible; animation-name: fadeInUp;\"><a href=\"https://portal.issn.org/resource/ISSN/3023-7343\"><img src=\"../images/issnlogo.png\" alt=\"openaccess\" width=\"200px\" /></a><p class=\"mb-0\">&nbsp;</p></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\" style=\"visibility: visible; animation-name: fadeInUp;\"><a href=\"https://archive.org/details/@tethys_environmental_science\"> <img src=\"../images/archive_logo.png\" alt=\"archive.org\" width=\"200px\" /><br /> </a><p class=\"mb-0\">www.archive.org</p></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\" style=\"visibility: visible; animation-name: fadeInUp;\"><a href=\"https://scholar.google.com/citations?user=IshBPScAAAAJ&amp;hl=en\"> <img src=\"../images/google_scholar_logo.png\" alt=\"scholar.google\" width=\"200px\" /><p class=\"mb-0\">&nbsp;</p></a></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\" style=\"visibility: visible; animation-name: fadeInUp;\"><a href=\"https://zenodo.org/records/10878150\"> <img title=\"zenodo \" src=\"../images/zenodo.png\" alt=\"zenodo \" width=\"200px\" /><p class=\"mb-0\">&nbsp;</p></a></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\" style=\"visibility: visible; animation-name: fadeInUp;\"><a href=\"https://www.base-search.net/Search/Results?type=all&amp;lookfor=Tethys+Environmental+Sciences&amp;ling=1&amp;oaboost=1&amp;keepFilters=1&amp;filter%5B%5D=f_dccollection%3A%22ftzenodo%22&amp;name=&amp;thes=&amp;refid=dcresen&amp;newsearch=1\"> <img title=\"indexcopernicus\" src=\"../images/base_logo.gif\" alt=\"www.base-search.net\" width=\"200px\" /><p class=\"mb-0\">&nbsp;</p></a></div><div class=\"col-lg-4 col-sm-6 wow fadeInUp\" style=\"visibility: visible; animation-name: fadeInUp;\"><a href=\"https://www.lifescience.net/page/httpstethysjournalcom/\"> <img title=\"lifescience\" src=\"../images/lifescience_logo.png\" alt=\"lifescience.net\" width=\"200px\" /><p class=\"mb-0\">&nbsp;</p></a></div><!--<div class=\"col-lg-4 col-sm-6 wow fadeInUp\" style=\"visibility: visible; animation-name: fadeInUp;\" _mce_style=\"visibility: visible; animation-name: fadeInUp;\"><a href=\"https://journals.indexcopernicus.com/search/details?id=131340\" _mce_href=\"https://journals.indexcopernicus.com/search/details?id=131340\"> <img title=\"indexcopernicus\" src=\"../images/ici_logo.png\" _mce_src=\"../images/ici_logo.png\" alt=\"indexcopernicus.com\" width=\"200px\" /><p class=\"mb-0\">&nbsp;</p></a></div>--><div class=\"col-lg-4 col-sm-6 wow fadeInUp\" style=\"visibility: visible; animation-name: fadeInUp;\"><a href=\"https://katalogplus.ub.uni-bielefeld.de/BASEModule/Search?join=AND&amp;lookfor0%5B%5D=Tethys+Environmental+Science&amp;type0%5B%5D=dcpublisher&amp;bool0%5B%5D=AND&amp;daterange%5B%5D=dcyear&amp;dcyearfrom=&amp;dcyearto=\"> <img title=\"indexcopernicus\" src=\"../images/bielefeld_unv_logo.png\" alt=\"katalogplus.ub.uni-bielefeld.de\" width=\"200px\" /><p class=\"mb-0\">&nbsp;</p></a></div></div></div></div>',1,'2024-03-20 19:38:04'),(7,'Contact','contact','<div class=\"col-12\"><div class=\"row gy-4 justify-content-center \"><div class=\"col-md-4 wow fadeIn\"><div class=\"d-flex align-items-center bg-light rounded p-4\"><div class=\"bg-white border rounded d-flex flex-shrink-0 align-items-center justify-content-center me-3\" style=\"width: 45px; height: 45px;\"><em class=\"fa fa-map-marker-alt text-primary\">&nbsp;</em></div><span><h3><strong>Contact</strong></h3>Tethys Environmental Science <br /> Modernevler Mah. 303. Sk. <br />No:9 D:1 P.C. 31300<br />İskenderun/Hatay, <br />Turkey</span></div></div></div></div><br /><div class=\"col-12\"><div class=\"row gy-4\"><div class=\"col-md-4 wow fadeIn\"><div class=\"d-flex align-items-center bg-light rounded p-4\" style=\"height: 200px;\"><div class=\"bg-white border rounded d-flex flex-shrink-0 align-items-center justify-content-center me-3\" style=\"width: 45px; height: 45px;\"><em class=\"fa fa-envelope-open text-primary\">&nbsp;</em></div><span><h5><strong>General Contact E-Mail</strong></h5>info@tethysjournal.com</span><br /><br /><br /></div></div><div class=\"col-md-4 wow fadeIn\"><div class=\"d-flex align-items-center bg-light rounded p-4\" style=\"height: 200px;\"><div class=\"bg-white border rounded d-flex flex-shrink-0 align-items-center justify-content-center me-3\" style=\"width: 45px; height: 45px;\"><em class=\"fa fa-envelope-open text-primary\">&nbsp;</em></div><span><h5><strong>Editorial Support Contact</strong></h5>Dr. Cemal TURAN<br />cemal.turan@tethysjournal.com<br />cemal.turan@yahoo.com <br />cemal.turan@iste.edu.tr</span></div></div><div class=\"col-md-4 wow fadeIn\"><div class=\"d-flex align-items-center bg-light rounded p-4\" style=\"height: 200px;\"><div class=\"bg-white border rounded d-flex flex-shrink-0 align-items-center justify-content-center me-3\" style=\"width: 45px; height: 45px;\"><em class=\"fa fa-envelope-open text-primary\">&nbsp;</em></div><span><h5><strong>Technical Support Contact</strong></h5>Dr. Yakup KUTLU<br />yakup.kutlu@tethysjournal.com<br />yakupkutlu@gmail.com <br />yakup.kutlu@iste.edu.tr</span></div></div></div></div>',1,'2024-03-20 19:38:04'),(8,'Announcement','announcement','<ul style=\"list-style-type: circle;\"><li><a href=\"https://dogavebilim.com/workshop_elasmo/\">International Workshop on Elasmobranchs, 05 July 2024, Iskenderun, Hatay, T&uuml;rkiye, (Face to face and online participation)</a></li></ul><ul style=\"list-style-type: circle;\"><li><strong><span style=\"font-size: medium;\"><a href=\"https://fsbi.org.uk/symposium-2025/\">FSBI 2025 Annual Symposium, 07-11 July 2025, Belfast</a><a href=\"https://fsbi.org.uk/symposium-2024/\"> </a></span></strong></li><li><strong><span style=\"font-size: medium;\"><a href=\"https://iczegar16.hzoos.gr/\"><strong>16th International Congress on the Zoogeography and Ecology of Greece and Adjacent Regions (ICZEGAR),</strong><span>&nbsp;03-06&nbsp;</span><strong>July 2025</strong>,&nbsp;</a><strong><a href=\"https://iczegar16.hzoos.gr/\"><strong>Athens, Greece</strong></a></strong></span></strong></li><li><strong><span style=\"font-size: medium;\"><a href=\"https://www.cmmi.blue/thalassa-2024/\">THALASSA 2024: Marine Sciences Conference, 28-29 May 2024, Larnaca, Cyprus</a></span></strong></li><li><strong><span style=\"font-size: medium;\"><a href=\"https://www.icens.eu/\">10th&nbsp;International Conference on Engineering and Natural Sciences, 02-06&nbsp;October 2024,Bosnia and Herzegovina</a></span></strong></li><li> <strong><span style=\"font-size: medium;\"><a href=\"https://esaconference.com/\"> The 5th International Conference on Environmental Science and Applications (ICESA 2024) , November 18, 2024 - November 20, 2024 | Lisbon, Portugal </a></span></strong></li><li> <strong><span style=\"font-size: medium;\"><a title=\"workshop2024\" href=\"https://dogavebilim.com/workshop2024/index.php\"><span>International Workshop on the Usage of Artificial Intelligence and Robotics in Environment and Health, December13, 2024, İskenderun, Hatay</span>, T&uuml;rkiye</a></span></strong></li></ul><ul><li><strong><span><a title=\"workshop2024\" href=\"https://dogavebilim.com/workshop2024/index.php\">International Workshop on the Usage of Artificial Intelligence and Robotics in Environment and Health, December13, 2024, İskenderun, Hatay, T&uuml;rkiye</a></span></strong></li></ul><ul style=\"list-style-type: circle;\"><li><strong>&nbsp;<a href=\"https://www.elasmobranch.nl/eea2025/\">European Elasmobranch Association Conference 2025, 29-30 October 2025,&nbsp;<span>Rotterdam, Netherland.</span></a></strong></li></ul>',1,'2024-03-20 19:38:04'),(9,'Content','content','',1,'2024-03-20 19:38:04'),(10,'Publication Ethics','policy','<div class=\"card-header\" style=\"text-align: justify;\"><br /><pre> <table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 30px;\"><span style=\"color: #ffffff;\">CONTENT</span></td></tr></tbody></table><br /><ul><li><p class=\"MsoNormal\" style=\"display: inline !important;\"><span style=\"color: #000000;\"><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"index.php?page=policy\">Publishers Ethic Rules </a></span></strong><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">&nbsp;</span></strong></span></p></li><li><span style=\"color: #000000;\"><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"index.php?page=policy#research\">Research Ethics</a></span></strong><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">&nbsp;</span></strong></span></li><li><span style=\"color: #000000;\"><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"index.php?page=policy#human\">Human Subjects and Animal Use in Research, Ethics Committee Approval and Informed Consent</a></span></strong><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">&nbsp;</span></strong></span></li><li><span style=\"color: #000000;\"><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"index.php?page=policy#conflict\">Conflict of Interest</a> </span></strong><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">&nbsp;</span></strong></span></li><li><span style=\"color: #000000;\"><a href=\"index.php?page=policy#authors\"><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">Authors Responsibilities</span></strong><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">&nbsp;</span></strong></a></span></li><li><span style=\"color: #000000;\"><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><a href=\"index.php?page=policy#responsibility\">Responsibility for the Editors and Reviewers</a> </span></strong><strong><span style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">&nbsp;</span></strong></span></li></ul></pre><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Publishers Ethic Rules</span></td></tr></tbody></table><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">The&nbsp;Tethys Environmantal Science is committed to upholding the highest standards of publication ethics and takes all possible measures against any publication malpractices. All authors submitting their works to <span>Tethys Environmantal Sciences&nbsp;</span>for publication as original articles attest that the submitted works represent their authors &nbsp;contributions and have not been copied or plagiarized in whole or in part from other works. The authors acknowledge that they have disclosed all and any actual or potential conflicts of interest with their work or partial benefits associated with it. In the same manner,&nbsp; <span>Tethys Environmantal Science&nbsp;</span>is committed to objective and fair single-blind peer-review of the submitted for publication works and to prevent any actual or potential conflict of interests between the editorial and review personnel and the reviewed material.is committed to objective and fair single-blind peer-review of the submitted for publication works and to prevent any actual or potential conflict of interests between the editorial and review personnel and the reviewed material.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">Further to the above, <span>Tethys Environmantal Science&nbsp;</span>provides a platform for the open public discussion of the journal contents. To secure accountability and to encourage sincere professional inputs without incivilities the system is set up to require registration and logging for recording of inputs. Some of the website contents will be available without logging but no single-blind peer review comments can be posted on the website without the disclosure of the reviewer identity to the journal editors.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">It is necessary to agree upon standards of expected ethical behavior for all parties involved in the act of publishing: the author, the journal editor, the single-blind peer reviewer and the publisher.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">Our ethic statements are based on&nbsp;<a href=\"https://publicationethics.org/\">COPE</a>s Best Practice Guidelines for Journal Editors.</span></p><p class=\"p\" style=\"text-align: justify;\"><strong>Publication Decisions</strong></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">The editor of the <span>Tethys Environmantal Science&nbsp;</span>is responsible for deciding which of the articles submitted to the journal should be published. The editor may be guided by the policies of the journal s editorial board and constrained by such legal requirements as shall then be in force regarding libel, copyright infringement and plagiarism. The editor may confer with other editors or reviewers in making this decision.</span></p><p class=\"p\" style=\"text-align: justify;\"><strong>Fair Play</strong></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">An editor at any time evaluate manuscripts for their intellectual content without regard to race, gender, sexual orientation, religious belief, ethnic origin, citizenship, or political philosophy of the authors.</span></p><p class=\"p\" style=\"text-align: justify;\"><strong>Confidentiality</strong></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">The editor and any editorial staff must not disclose any information about a submitted manuscript to anyone other than the corresponding author, reviewers, potential reviewers, other editorial advisers, and the publisher, as appropriate.</span></p><p class=\"p\" style=\"text-align: justify;\"><strong>Disclosure and Conflicts of Interest</strong></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">Unpublished materials disclosed in a submitted manuscript must not be used in an editor s own research without the express written consent of the author.</span></p><hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Research Ethics</span></td></tr></tbody></table><a name=\"research\"> </a><h4 class=\"card-title m-0 pl-1\"><strong><a class=\"accordion-toggle collapsed from-journal\"> </a></strong></h4><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">An approval of research protocols by the Ethics Committee in accordance with international agreements (World Medical Association Declaration of Helsinki &ldquo;Ethical Principles for Medical Research Involving Human Subjects,&rdquo; amended in October 2013,&nbsp;<a href=\"http://www.wma.net/\">www.wma.net</a>) is required for experimental, clinical, and drug studies. If required, ethics committee reports or an equivalent official document will be requested from the authors.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">For manuscripts concerning experimental research on humans, a statement should be included that shows the written informed consent of patients and volunteers was obtained following a detailed explanation of the procedures that they may undergo. Information on patient consent, the name of the ethics committee, and the ethics committee approval number should also be stated in the Materials and Methods section of the manuscript. It is the authors &nbsp;responsibility to carefully protect the patients &nbsp;anonymity. For photographs that may reveal the identity of the patients, signed releases of the patient or of their legal representative should be enclosed.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><span>Tethys Environmantal Science&nbsp;</span>requires experimental research studies on vertebrates or any regulated invertebrates to comply with relevant institutional, national and/or international guidelines. The journal supports the principles of Basel Declaration (basel-declaration.org) and the guidelines published by International Council for Laboratory Animal Science (ICLAS) (iclas.org). Authors are advised to clearly state their compliance with relevant guidelines.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><span>Tethys Environmantal Science&nbsp;</span>advises authors to comply with IUCN Policy Statement on Research Involving Species at Risk of Extinction and the Convention on the Trade in Endangered Species of Wild Fauna and Flora for research involving plants.</span></p><hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Human Subjects and Animal Use in Research, Ethics Committee Approval and Informed Consent Rules</span></td></tr></tbody></table><a name=\"human\"> </a><h4 class=\"card-title m-0 pl-1\"><strong><a class=\"accordion-toggle collapsed from-journal\"> </a></strong></h4><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><span>Tethys Environmantal Science</span>&nbsp;takes as principle to comply with the ethical standards of&nbsp;<a href=\"https://www.wma.net/policies-post/wma-declaration-of-helsinki-ethical-principles-for-medical-research-involving-human-subjects/\">World Medical Association (WMA) Declaration of Helsinki &ndash; Ethical Principles for Medical Research Involving Human Subjects</a>&nbsp;and&nbsp;<a href=\"https://www.wma.net/policies-post/wma-statement-on-animal-use-in-biomedical-research/\">WMA Statement on Animal Use in Biomedical Research</a>.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><a href=\"https://www.wma.net/policies-post/wma-declaration-of-helsinki-ethical-principles-for-medical-research-involving-human-subjects/\"><span style=\"text-decoration: underline;\">https://www.wma.net/policies-post/wma-declaration-of-helsinki-ethical-principles-for-medical-research-involving-human-subjects/</span></a></span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">https://www.wma.net/policies-post/wma-statement-on-animal-use-in-biomedical-research/</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">An approval of research protocols by the Ethics Committee in accordance with international standards mentioned above is required for experimental, clinical, and drug studies and for some case reports. If required, ethics committee reports or an equivalent official document will be requested from the authors. For manuscripts concerning experimental research on humans, a statement should be included that shows that written informed consent of patients and volunteers was obtained following a detailed explanation of the procedures that they may undergo. For studies carried out on animals, the measures taken to prevent pain and suffering of the animals should be stated clearly. Information on patient consent, the name of the ethics committee, and the ethics committee approval number should also be stated in the Materials and Methods section of the manuscript. It is the authors &nbsp;responsibility to carefully protect the patients &nbsp;anonymity. For photographs that may reveal the identity of the patients, signed releases of the patient or of their legal representative should be enclosed.</span></p><hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Conflict of Interest</span></td></tr></tbody></table><a name=\"conflict\"> </a><h4 class=\"card-title m-0 pl-1\"><strong><a class=\"accordion-toggle collapsed from-journal\"> </a></strong></h4><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><span>Tethys Environmantal Science</span>&nbsp;requires the authors and all individuals taking part in the evaluation process to disclose any existing or potential conflict of interest (such as financial ties, academic commitments, personal relationships, institutional affiliations) that could unduly influence one s responsibilities. &nbsp;To disclose potential conflicts of interest, the&nbsp;<a href=\"https://cdn.istanbul.edu.tr/file/JTA6CLJ8T5/C70AC589A76B45429D1A243CA3C4849D\">ICMJE Potential Conflict of Interest Disclosure Form</a>&nbsp;should be filled in and submitted by authors as explained in the Author Form of the journal. Cases of a potential conflict of interest are resolved &nbsp;within the scope of&nbsp;<a href=\"https://publicationethics.org/resources/flowcharts/complete-set-english\">COPE Conflict of Interest Flowcharts</a>&nbsp;and&nbsp;<a href=\"https://www.icmje.org/recommendations/\">ICMJE Conflict of Interest guidelines</a></span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">Besides conflict of interest, all financial support received to carry out research must be declared while submitting the paper.</span></p><hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Authors Responsibilities</span></td></tr></tbody></table><a name=\"author\"> </a><h4 class=\"card-title m-0 pl-1\"><strong><a class=\"accordion-toggle collapsed from-journal\"> </a></strong></h4><p class=\"p\" style=\"text-align: justify;\"><strong>Reporting Standards</strong></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">Authors of reports of original research should present an accurate account of the work performed as well as an objective discussion of its significance. Underlying data should be represented accurately in the paper. A paper should contain sufficient detail and references to permit others to replicate the work. Fraudulent or knowingly inaccurate statements constitute unethical behavior and are unacceptable.</span></p><p class=\"p\" style=\"text-align: justify;\"><strong>Data Access and Retention</strong></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">Authors are asked to provide the raw data in connection with a paper for editorial review, and should be prepared to provide public access to such data (consistent with the ALPSP-STM Statement on Data and Databases), if practicable, and should in any event be prepared to retain such data for a reasonable time after publication.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Originality and Plagiarism</strong></span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">The authors should ensure that they have written entirely original works, and if the authors have used the work and/or words of others that this has been appropriately cited or quoted.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">By submitting articles to&nbsp;<span>Tethys Environmantal Science</span>, the author attest the following:</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">&middot;&nbsp;&nbsp;None of the part of manuscript is plagiarized from other sources</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">&middot;&nbsp;&nbsp;Proper reference is provided for all contents extracted from other sources</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">Strong action will be taken against cases of plagiarism</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">All the papers submitted have to pass through an initial screening and will be checked through the Advanced Plagiarism Dectection Softwares (iThenticate).</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Multiple, Redundant or Concurrent Publication</strong></span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">An author should not in general publish manuscripts describing essentially the same research in more than one journal or primary publication. Submitting the same manuscript to more than one journal concurrently constitutes unethical publishing behaviour and is unacceptable.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Acknowledgement of Sources</strong></span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">Proper acknowledgment of the work of others must always be given. Authors should cite publications that have been influential in determining the nature of the reported work.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Authorship of the Paper</strong></span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">Authorship should be limited to those who have made a significant contribution to the conception, design, execution, or interpretation of the reported study. All those who have made significant contributions should be listed as co-authors. Where there are others who have participated in certain substantive aspects of the research project, they should be acknowledged or listed as contributors.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">The corresponding author should ensure that all appropriate co-authors and no inappropriate co-authors are included on the paper, and that all co-authors have seen and approved the final version of the paper and have agreed to its submission for publication.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Hazards and Human or Animal Subjects</strong></span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">If the work involves chemicals, procedures or equipment that have any unusual hazards inherent in their use, the author must clearly identify these in the manuscript.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Disclosure and Conflicts of Interest</strong></span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">All authors should disclose in their manuscript any financial or other substantive conflict of interest that might be construed to influence the results or interpretation of their manuscript. All sources of financial support for the project should be disclosed.</span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Fundamental Errors in Published Works</strong></span></p><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\">When an author discovers a significant error or inaccuracy in his/her own published work, it is the author s obligation to promptly notify the journal editor or publisher and cooperate with the editor to retract or correct the paper.</span></p><hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Responsibility for the Editors and Reviewers</span></td></tr></tbody></table><a name=\"responsibility\"> </a><h4 class=\"card-title m-0 pl-1\"><strong><a class=\"accordion-toggle collapsed from-journal\"> </a></strong></h4><p class=\"p\" style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>General duties and responsibilities for editors;</strong></span></p><ul style=\"text-align: justify;\"><li><span style=\"color: #000000;\">Actively seek the views of authors, readers, reviewers and editorial board members about ways of improving their journal s processes</span></li><li><span style=\"color: #000000;\">Encourage and be aware of research into single-blind peer review and &lsquo;journalology &nbsp;and reassess journal processes in the light​of new findings</span></li><li><span style=\"color: #000000;\">Work to persuade their publishers to provide them with appropriate resources, guidance from experts (e.g. designers,</span><br /><span style=\"color: #000000;\">lawyers) and adequate training to perform their role in a professional manner and raise the quality of their journal</span></li><li><span style=\"color: #000000;\">Support initiatives designed to reduce academic misconduct</span></li><li><span style=\"color: #000000;\">Support initiatives to educate researchers about publication ethics</span></li><li><span style=\"color: #000000;\">Assess the effects of their journal policies on author and reviewer behaviour and revise policies, as required, to</span><br /><span style=\"color: #000000;\">encourage responsible behaviour and discourage misconduct</span></li><li><span style=\"color: #000000;\">Ensure that any press releases issued by the journal reflect the message of the reported article and put it into context</span></li></ul><p class=\"p\" style=\"text-align: justify;\"><strong>Duties of Reviewers;</strong></p><ul><li style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Contribution to Editorial Decisions</strong>:&nbsp;Single-blind peer review assists the editor in making editorial decisions and through the editorial communications with the author may also assist the author in improving the paper.</span></li><li style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Promptness:&nbsp;</strong>Any selected referee who feels unqualified to review the research reported in a manuscript or knows that its prompt review will be impossible should notify the editor and excuse himself from the review process.</span></li><li style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Confidentiality:&nbsp;</strong>Any manuscripts received for review must be treated as confidential documents. They must not be shown to or discussed with others except as authorized by the editor.</span></li><li style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Standards of Objectivity:&nbsp;</strong>Reviews should be conducted objectively. Personal criticism of the author is inappropriate. Referees should express their views clearly with supporting arguments.</span></li><li style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Acknowledgement of Sources:&nbsp;</strong>Reviewers should identify relevant published work that has not been cited by the authors. Any statement that an observation, derivation, or argument had been previously reported should be accompanied by the relevant citation. A reviewer should also call to the editor s attention any substantial similarity or overlap between the manuscript under consideration and any other published paper of which they have personal knowledge.</span></li><li style=\"text-align: justify;\"><span style=\"color: #000000;\"><strong>Disclosure and Conflict of Interest:&nbsp;</strong>Privileged information or ideas obtained through single-blind peer review must be kept confidential and not used for personal advantage. Reviewers should not consider manuscripts in which they have conflicts of interest resulting from competitive, collaborative, or other relationships or connections with any of the authors, companies, or institutions connected to the papers.</span></li></ul></div>',1,'2024-03-20 19:38:04'),(11,'Publication Ethics and Malpractice Statement','ethic','<!-- 		@page { margin: 0.79in } 		p { margin-bottom: 0.1in; direction: ltr; line-height: 120%; text-align: left; orphans: 2; widows: 2 } 		a:link { color: #0563c1 } 	 --><p class=\"p0\"><span><strong><span style=\"font-size: medium;\">&nbsp;&nbsp;<br />Public Policy of Tethys Envioronmental Science<br /></span></strong></span><strong>Peer Review</strong></p><p><span>All manuscripts are subject to at least&nbsp;double&nbsp;peer reviews and are expected to meet standards of significance and academic excellence. If approved by the editor, submissions will be considered by reviewers, whose identities will remain anonymous to the authors.</span></p><p><strong>Ethics</strong><br />The Author declares that the manuscript is original and has not been published elsewhere in any form, that it has not been submitted to any journal/proceedings and that it will not be submitted to any other journal/proceedings. The Author is responsible for the research and results described in the paper&nbsp;If it is accepted for publication in the Tethys Environmental Sciences.&nbsp;If the article is a joint work of several authors (co-authors), the Author who submits the article declares that any person named as author (co-author) of the Article is aware of the requirements of this agreement and has agreed to be so named.&nbsp;The Author warrants that the article does not infringe upon any copyright, contains no libelous or otherwise unlawful statements and does not otherwise infringe on the rights of others.&nbsp;The Author transfers the copyright for this publication/article to the Publisher.&nbsp;The Author licenses to the Publisher the right to distribute the Article as a part of Tethys Environmental Sciences.<br />Authors must follow the national and international ethical standards for all kind of experiments (both on human beings, and on animals).</p><p><strong>Plagiarism</strong><br />Tethys Environmental Sciences uses the Plagiarism software to detect instances of overlapping and similar text in submitted manuscripts. Manuscripts that are found to have been plagiarized from a manuscript by other authors, whether published or unpublished, will incur plagiarism sanctions.</p><p><strong>Copyright</strong><br />Open Access authors retain the copyrights of their papers, and all open access articles are distributed under the terms of the Creative Commons Attribution License, which permits unrestricted use, distribution, and reproduction in any medium, provided that the original work is properly cited.&nbsp;<br />All published works in the Tethys Environmental Sciences is licensed under a Creative Commons Attribution 4.0 International License which permits anyone to copy, redistribute, remix, transmit and adapt the work provided the original work and source is appropriately cited.</p><p><strong>Open Access</strong><br />Tethys Environmental Sciences&nbsp;is an open access journal which means that all content is freely available without charge to the user or his/her institution. Users are allowed to read, download, copy, distribute, print, search, or link to the full texts of the articles in this journal without asking prior permission from the publisher or the author. This is in accordance with the Budapest Open Access Initiative (BOAI) definition of open access.</p><p><strong>Conflicts of Interest</strong><br />Authors must declare all potential interests whether or not they actually had an influence on a &lsquo;<strong>Compliance with Ethical Standards</strong>&rsquo; section, which should explain why the interest may be a conflict. If there are none, the authors should state &ldquo;The author(s) declare(s) that there is no conflict of interest regarding the publication of this article.&rdquo; Submitting authors are responsible for co-authors declaring their interests. All funding, whether a conflict or not, must be declared. The involvement of anyone other than the authors who 1) has an interest in the outcome of the work; 2) is affiliated to an organization with such an interest; or 3) was employed or paid by a funder, in the commissioning, conception, planning, design, conduct, or analysis of the work, the preparation or editing of the manuscript or the decision to publish must be declared at the&nbsp;<strong>Conflict of Interest</strong>.<br />When reporting studies that involve&nbsp;<strong>Welfare of Animals and/or Human Rights,&nbsp;</strong>&nbsp;authors should include a relevant statement as described in the Guide for authors.&nbsp;</p>',1,'2024-03-20 19:38:04'),(12,'Aim & Scope','aim_scope','<br /><br /> <hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Aim</span></td></tr></tbody></table><br />Tethys Environmantal Science is a single-blind peer-reviewed journal that provides publication of articles in topical areas of Environmantal Science. <span>Tethys Environmantal Science aims to contribute to the literature by publishing manuscripts at the highest scientific level on all fields of Environmantal Science. Tethys Environmental Science</span>&nbsp;is published trimesterly and does not charge any processing and publication fee. The publication language of the journal is English. The goal of this journal is to provide a platform for researchers, students, professionals and academicians all&nbsp; over the world to combine, promote, share, and discuss new ideas, issues, developments and its application in different areas of Environmantal Science. The journal publishes original research articles, short communications, technical notes, reports and review articles.&nbsp;<br /><br /> <table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Scope</span></td></tr></tbody></table><br /> <br />Tethys Environmental Science welcomes the submission of manuscripts that meet the general criteria of significance and scientific excellence and publishes single-blind peer reviewed&nbsp; articals covering topical areas given below with a global impact;&nbsp;<br />-river ecosystem,<br />-marine ecosystem,<br />-terrestrial ecosystem,<br />-conservation biology,<br />-ecology,<br />-environmental pollution,<br />-marine and freshwater biodiversity,<br />-fisheries biology,<br />-fisheries,<br />-aquaculture,<br />-agriculture,<br />-alien invasion,<br />-molecular ecology,<br />-biotechnology,<br />-food preccessing,<br /><strong>and also the use of</strong><br />-biosensors,<br /><span>-biomedical,</span><br /><span>-natural medicine,<br /><span>-genetic algorithms,</span></span><br />-artificial intelligence,<br />-innovative computations,<br />-machine learning,<br />-deep learning,<br />-materials&nbsp;<span>in environmental problems at a regional or global scale</span><strong><br /></strong>in the form of original research articles, case studies, reviews and essays&nbsp;on the determined topics at the scope.&nbsp;<p>&nbsp;</p><p><br />&nbsp;<br /></p>',1,'2024-03-20 19:38:04'),(13,'Peer Review Policy','pppolicy','<div class=\"card-header\" style=\"text-align: justify;\"><br /><pre>  <table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">CONTENT</span></td></tr></tbody></table> <br /><ul style=\"font-family: Calibri; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><li><strong><strong> <a href=\"index.php?page=pppolicy\">Publication Policy </a></strong></strong></li><li><strong><strong> <a href=\"index.php?page=pppolicy#openaccess\">Open Access Statement </a></strong></strong></li><li><strong><strong> <a href=\"index.php?page=pppolicy#openaccess\">Article Processing Charge</a> </strong></strong></li><li><strong><strong> <a href=\"index.php?page=pppolicy#copyright\">Copyright Notice</a> </strong></strong></li><li><strong><strong> <a href=\"index.php?page=pppolicy#policy\">Peer Review Policies</a> </strong></strong></li><li><strong><strong> <a href=\"index.php?page=pppolicy#withdrawal\">Article withdrawal Policy</a></strong></strong></li><li><strong><strong> <strong><a href=\"index.php?page=pppolicy#complaints\">Complaints &amp; Appeals Policy</a></strong></strong></strong></li><li><strong><strong><strong> <strong><a href=\"index.php?page=pppolicy#advertising\">Advertising Policy</a></strong></strong></strong></strong></li><li><strong><strong><strong> <strong><a href=\"index.php?page=pppolicy#marketing\">Direct Marketing</a> </strong></strong></strong></strong></li><li><strong><strong><strong> <strong><a href=\"index.php?page=pppolicy#prp\">Single-blind peer Review Process</a> </strong></strong></strong></strong></li><li><strong><strong><strong> <a href=\"index.php?page=pppolicy#archiving\">Repository and Self-Archiving Policy</a><br /></strong></strong></strong></li><li><strong><strong><strong> <a href=\"index.php?page=pppolicy#archiving\">I4OC standards for open citations</a><br /></strong></strong></strong></li><li><strong><strong><strong><strong> <a href=\"index.php?page=pppolicy#supplement\">Peer Review Policies for Supplements</a></strong></strong></strong></strong></li></ul></pre><a name=\"pppolicy\"> <table class=\"bg-blue2\" style=\"width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Publication Policy</span></td></tr></tbody></table></a><div class=\"card-header\"><a name=\"pppolicy\"> </a><div class=\"collapse show\"><a name=\"pppolicy\"> </a><div class=\"card-body\"><a name=\"pppolicy\"> </a><p><a name=\"pppolicy\"><span style=\"text-align: start;\">Tethys Environmental Science</span><span>&nbsp;is committed to upholding the highest standards of publication ethics and pays regard to Principles of Transparency and Best Practice in Scholarly Publishing published by&nbsp;</span></a><a href=\"https://publicationethics.org/\" target=\"_blank\">the Committee on Publication Ethics (COPE)</a>,&nbsp;<a href=\"https://doaj.org/apply/transparency/#principles-of-transparency-and-best-practice-in-scholarly-publishing\" target=\"_blank\">the Directory of Open Access Journals (DOAJ)</a>,&nbsp;<a href=\"https://oaspa.org/\" target=\"_blank\">the Open Access Scholarly Publishers Association (OASPA)</a>, and&nbsp;<a href=\"https://www.wame.org/\" target=\"_blank\">the World Association of Medical Editors (WAME)</a>&nbsp;on&nbsp;<a href=\"https://publicationethics.org/resources/guidelines-new/principles-transparency-and-best-practice-scholarly-publishing\" target=\"_blank\"><span>https://publicationethics.org/resources/guidelines-new/principles-transparency-and-best-practice-scholarly-publishing</span></a><span>&nbsp;</span></p><p><span>The subjects covered in the manuscripts submitted to&nbsp;</span><span style=\"text-align: start;\">Tethys Environmental Science&nbsp;</span><span>for publication must be in accordance with the aim and scope of the Journal. Only those manuscripts approved by every individual author and that were not published before in or sent to another journal, are accepted for evaluation.</span></p><p><span>Changing the name of an author (omission, addition or order) in papers submitted to the Journal requires written permission of all declared authors.</span></p><p><span>Plagiarism, duplication, fraud authorship/denied authorship, research/data fabrication, salami slicing/salami publication, breaching of copyrights, prevailing conflict of interest are unethical behaviors. All manuscripts not in accordance with the accepted ethical standards will be removed from the publication. This also contains any possible malpractice discovered after the publication.</span></p><p><strong><em>Plagiarism</em></strong><span><br />Submitted manuscripts that pass preliminary control are scanned for plagiarism using iThenticate software. If plagiarism/self-plagiarism will be found authors will be informed. Editors may resubmit manuscript for similarity check at any single-blind peer-review or production stage if required. High similarity scores may lead to rejection of a manuscript before and even after acceptance. Depending on the type of article and the percentage of similarity score taken from each article, the overall similarity score is expected to be less than 20% without references</span></p><p><strong><em>Peer-Review</em></strong><span><br />After plagiarism check, the eligible ones are evaluated by the editors for their originality, methodology, the importance of the subject covered and compliance with the journal scope. The editor provides a fair single-blind peer review of the submitted articles and hands over the papers matching the formal rules to at least two national/international referees for evaluation and gives green light for publication upon modification by the authors in accordance with the referees&rsquo; claims.<br /></span></p></div></div></div><hr /><a name=\"openaccess\"> <table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Open Access Statement</span></td></tr></tbody></table></a><div class=\"card-header\"><a name=\"openaccess\"> </a><div class=\"collapse show\"><a name=\"openaccess\"> </a><div class=\"card-body\"><a name=\"openaccess\"> </a><p><a name=\"openaccess\"><span> The journal is an open access journal and all content is freely available without charge to the user or his/her institution.   Users are allowed to read, download, copy, distribute, print, search, or link to the full texts of the articles in this journal, including for commercial purposes, without asking prior permission from the publisher or the author. This is in accordance with the Creative Commons Attribution 4.0 International (CC BY 4.0) license. </span></a></p><p><span>The open access articles in the journal are licensed under the terms of the Creative Commons Attribution 4.0 International (</span><a href=\"https://creativecommons.org/licenses/by/4.0/deed.en\" target=\"_blank\"><span>CC BY 4.0</span></a><span>) license( which is contained in page of  <a href=\"../index.php?page=copyright_and_licensing\">Copyright and Licensing of journal.</a>). <br /><br /> The journal applies the Creative Commons Attribution 4.0 International (CC BY 4.0) license to all published works. Authors retain copyright and the publisher holds a non-exclusive license to publish the material. </span></p></div></div></div><hr /><a name=\"openaccess\"> <table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Article Processing Charge</span></td></tr></tbody></table></a><div class=\"card-header\"><a name=\"openaccess\"></a><a name=\"processing\"> </a><div class=\"collapse show\"><div class=\"card-body\"><p><span>Processing and publication are free of charge with the journal. There is no article processing charges or submission fees for any submitted or accepted articles.</span></p></div></div></div><hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Copyright Notice</span></td></tr></tbody></table><div class=\"card-header\"><a name=\"copyright\"> </a><h4 class=\"card-title m-0 pl-1\"><strong><a class=\"accordion-toggle collapsed from-journal\"></a></strong></h4><div class=\"collapse show\"><div class=\"card-body\"><p><span> Authors publishing with Tethys Environmental Science retain full copyright of their work( which is contained in page of  <a href=\"../index.php?page=copyright_and_licensing\">Copyright and Licensing of journal.</a>). Articles are published under the CC BY 4.0 license (<a href=\"https://creativecommons.org/licenses/by/4.0/\" target=\"_blank\">CC BY 4.0</a>) (<a href=\"https://creativecommons.org/licenses/by/4.0/\" target=\"_blank\">https://creativecommons.org/licenses/by/4.0/</a>&nbsp;) , which allows for unrestricted use, distribution, and reproduction in any medium, provided the original work is properly cited. The publisher receives a non-exclusive license to publish the article.  CC BY 4.0 license permits unrestricted use, distribution, and reproduction in any medium, provided the original work is properly cited.<br /> <br /></span></p>The jornal is free to:<br /> Share &mdash; copy and redistribute the material in any medium or format for any purpose, even commercially.<br /> Adapt &mdash; remix, transform, and build upon the material for any purpose, even commercially.<br /> The licensor cannot revoke these freedoms as long as you follow the license terms.<br /> Under the following terms:<br /> Attribution &mdash; You must give appropriate credit , provide a link to the license, and indicate if changes were made . You may do so in any reasonable manner, but not in any way that suggests the licensor endorses you or your use.<br /> No additional restrictions &mdash; You may not apply legal terms or technological measures that legally restrict others from doing anything the license permits.</div></div></div><hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Peer Review Policies</span></td></tr></tbody></table><h4 class=\"card-title m-0 pl-1\"><strong><a class=\"accordion-toggle collapsed from-journal\"></a></strong></h4><div class=\"card-header\"><a name=\"policy\"><div class=\"collapse show\"><div class=\"card-body\"><p><span>Only those manuscripts approved by its every individual author and that were not published before in or sent to another journal, are accepted for evaluation.</span></p><p><span>Submitted manuscripts that pass preliminary control are scanned for plagiarism using iThenticate software. After plagiarism check, the eligible ones are evaluated by editors for their originality, methodology, the importance of the subject covered and compliance with the journal scope.</span></p><p><span>The editor hands over the papers matching the formal rules to at least two national/international referees for single-blind peer review evaluation and gives green light for publication upon modification by the authors in accordance with the referees&rsquo; claims.&nbsp;</span>Editors will consider the single-blind peer-reviewed reports when making a decision, but are not bound by the opinions or recommendations therein. A concern raised by a  single-blind peer reviewer or the Editor themself may result in the manuscript being rejected. Authors receive single-blind peer review reports with the editorial decision on their manuscript.</p></div></div></a></div><a name=\"policy\"> <hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Article withdrawal Policy</span></td></tr></tbody></table></a><h4 class=\"card-title m-0 pl-1\"><a name=\"policy\"><strong>&nbsp;</strong></a><strong><a class=\"accordion-toggle collapsed from-journal\"></a></strong></h4><div class=\"card-header\"><a name=\"polwithdrawal\"><div class=\"collapse show\"><div class=\"card-body\"><p>Only used for Articles in Press which represent early versions of articles and sometimes contain errors, or may have been accidentally submitted twice. Occasionally, but less frequently, the articles may represent infringements of professional ethical codes, such as multiple submission, bogus claims of authorship, plagiarism, fraudulent use of data or the like. Articles in Press (articles that have been accepted for publication but which have not been formally published and will not yet have the complete volume/issue/page information) that include errors, or are discovered to be accidental duplicates of other published article(s), or are determined to violate our journal publishing ethics guidelines in the view of the editors (such as multiple submission, bogus claims of authorship, plagiarism, fraudulent use of data or the like), may be &ldquo;Withdrawn&rdquo; from&nbsp;<span style=\"text-align: start;\">Tethys Environmental Science</span>. Withdrawn means that the article content (HTML and PDF) is removed and replaced with a HTML page and PDF simply stating that the article has been withdrawn according to the&nbsp;<span style=\"text-align: start;\">Tethys Environmental Science&nbsp;</span>Policy on Article in Press Withdrawal with a link to the current policy&nbsp;document.</p></div></div></a></div><a name=\"polwithdrawal\"> <hr /></a><a name=\"complaints\"> </a> <table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Complaints &amp; Appeals Policy</span></td></tr></tbody></table><a name=\"prp\"> </a><div class=\"card-header\"><div class=\"collapse show\" style=\"text-align: justify;\"><div class=\"card-body\"><p>Complaints regarding any published materials will only be accepted within 12 months from the first publication date. In case of any complaint, the authors are required to submit their complaints along with their reasons to the editorial office via <a href=\"mailto:info@tethysjournal.com\"> info@tethysjournal.com </a> e-mail address. The complaint is handled by the Editor-in-Chief and/or Manager Editor.  The Editor-in-Chief together with Manager Editor will investigate the matter. The complainant will be given appropriate feedback. Feedback is provided to relevant stakeholders to improve processes and procedures.</p></div></div></div><hr /><a name=\"advertising\"> </a> <table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Advertising Policy</span></td></tr></tbody></table><a name=\"prp\"> </a><div class=\"card-header\"><div class=\"collapse show\" style=\"text-align: justify;\"><div class=\"card-body\"><p>Tethys Environmental Science does not accept commercial advertising for its periodicals, web site, and other forms of communication.</p></div></div></div><hr /><a name=\"marketing\"> </a> <table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Direct Marketing</span></td></tr></tbody></table><a name=\"prp\"> </a><div class=\"card-header\"><div class=\"collapse show\" style=\"text-align: justify;\"><div class=\"card-body\"><p>There is no direct marketing activity conducted on behalf of the journal of Tethys Environmental Science.</p></div></div></div><hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Responsibility for the Editor and Reviewers</span></td></tr></tbody></table><h4 class=\"card-title m-0 pl-1\"><a name=\"polwithdrawal\"><strong>&nbsp;</strong></a><strong><a class=\"accordion-toggle collapsed from-journal\"></a></strong></h4><div class=\"card-header\"><a name=\"Responsibility\"><div class=\"collapse show\"><div class=\"card-body\"><p><span>Editors evaluate manuscripts for their scientific content without regard to ethnic origin, gender, citizenship, religious belief or political philosophy of the authors. Editors provide a fair single-blind peer review of the submitted articles for publication and ensures that all the information related to submitted manuscripts is kept as confidential before publishing.</span></p><p><span>Editors are responsible for the contents and overall quality of the publication. He/She must publish errata pages or make corrections when needed.</span></p><p><span>Editors do not allow any conflicts of interest between the authors, editors and reviewers. Only he/she has the full authority to assign a reviewer and is responsible for final decision for publication of the manuscripts in the Journal.</span></p><p><span>Reviewers must have no conflict of interest with respect to the research, the authors and/or the research funders. Their judgments must be objective.</span></p><p><span>Reviewers must ensure that all the information related to submitted manuscripts is kept as confidential and must report to the editor if they are aware of copyright infringement and plagiarism on the author&rsquo;s side.</span></p><p><span>A reviewer who feels unqualified to review the topic of a manuscript or knows that its prompt review will be impossible should notify the editor and excuse himself from the review process.</span></p></div></div></a></div><a name=\"Responsibility\"> </a> <hr /><a name=\"processing\"> </a> <table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Peer Review Process</span></td></tr></tbody></table><a name=\"prp\"> </a><div class=\"card-header\"><div class=\"collapse show\" style=\"text-align: justify;\"><div class=\"card-body\"><p><span>Only those manuscripts approved by its every individual author and that were not published before in or sent to another journal, are accepted for evaluation.</span></p><p><span>Submitted manuscripts that pass preliminary control are scanned for plagiarism using iThenticate software. After plagiarism check, the eligible ones are evaluated by Editors&nbsp;&nbsp;</span>for their originality, methodology, the importance of the subject covered and compliance with the journal scope.</p><p><span>Editors evaluate manuscripts for their scientific content without regard to ethnic origin, gender, citizenship, religious belief or political philosophy of the authors and ensures a fair single-blind peer review of the selected manuscripts.</span></p><p><span>The selected manuscripts are sent to at least two national/international referees for evaluation and publication decision is given by Editors upon modification by the authors in accordance with the referees&rsquo; claims.</span></p><p><span>Editors do not allow any conflicts of interest between the authors, editors and reviewers and is responsible for final decision for publication of the manuscripts in the Journal.</span></p><p><span>Reviewers&rsquo; judgments must be objective. Reviewers&rsquo; comments on the following aspects are expected while conducting the review.</span></p><p><span>- Does the manuscript contain new and significant information?</span></p><p><span>- Does the abstract clearly and accurately describe the content of the manuscript?</span></p><p><span>- Is the problem significant and concisely stated?</span></p><p><span>- Are the methods described comprehensively?</span></p><p><span>- Are the interpretations and consclusions justified by the results?</span></p><p><span>- Is adequate references made to other Works in the field?</span></p><p><span>- Is the language acceptable?</span></p><p><span>Reviewers must ensure that all the information related to submitted manuscripts is kept as confidential and must report to the editor if they are aware of copyright infringement and plagiarism on the author&rsquo;s side.</span></p><p><span>A reviewer who feels unqualified to review the topic of a manuscript or knows that its prompt review will be impossible should notify the editor and excuse himself from the review process.<br /></span></p><a name=\"archiving\"> </a></div></div></div><hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">&gt;Repository and Self-Archiving Policy</span></td></tr></tbody></table><div class=\"card-header\"><div class=\"collapse show\" style=\"text-align: justify;\"><div class=\"card-body\"><a name=\"supplement\"> </a> <br /><p><span> To guarantee that all papers published in the journal are maintained and permanently accessible, articles are stored in the open repository Zenodo (https://zenodo.org) and internet archive (https://archive.org/) which serve as an international archival web site and at the same time permits LOCKSS to collect, preserve, and serve the content.   <br /> Additionally, authors are encouraged to self-archive the final PDF version of their articles in any institutional or subject repository such as Sherpa/Romeo, Dulcinea, Diadorim, Mir@bel or other repository of the author&rsquo;s choice. Authors should provide a link from the deposited version to the URL of IUPress journal website. .</span></p></div></div></div><hr /><table style=\"background: #1363c6; width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">I4OC standards for open citations</span></td></tr></tbody></table><div class=\"card-header\"><div class=\"collapse show\" style=\"text-align: justify;\"><div class=\"card-body\"><a name=\"supplement\"> </a> <br /><p><span> Cappadocia Journal of Education (KAPED) shares references in accordance with I4OC standards. <a href=\"https://i4oc.org/#goals\">I4OC standards</a> require references to be structured, separable and clear.  .</span></p></div></div></div><hr /><table style=\"background: #1363c6; width: 100%;\" border=\"0\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Single-blind peer Review Policies for Supplement</span></td></tr></tbody></table><div class=\"card-header\"><a name=\"processing\"> </a><div class=\"collapse show\"><div class=\"card-body\"><p>Only those manuscripts approved by its every individual author and that were not published before in or sent to another journal, congress, conference etc. are accepted for evaluation.</p><p>Submitted manuscripts that pass preliminary control are scanned for plagiarism using iThenticate software. After plagiarism check, the eligible ones are evaluated by the editors for their originality, methodology, the importance of the subject covered and compliance with the journal scope.</p><p>The editor hands over the papers matching the formal rules to at least two national/international referees for single-blind peer review evaluation and gives green light for publication upon modification by the authors in accordance with the referees&rsquo; claims.<br /><br /><br /></p><p><br /><br /></p></div></div></div><br /><br /><div id=\"_mcePaste\" class=\"mcePaste\" style=\"position: absolute; left: -10000px; top: 1620px; width: 1px; height: 1px; overflow: hidden;\"><h4 class=\"card-title m-0 pl-1\" style=\"font-size: 10px;\"><span style=\"color: #000000;\">Supplements&nbsp;</span></h4></div></div>',1,'2024-03-20 19:38:04'),(14,'Copyright and Licensing','copyright_and_licensing','\r\n\r\n<table class=\"bg-blue2\" style=\"width: 100%;\" border=\"1\"><tbody><tr><td style=\"padding-left: 2px;\"><span style=\"color: #ffffff;\">Copyright and Licensing</span></td></tr></tbody></table></a><div class=\"card-header\">   <div class=\"collapse show\">  <div class=\"card-body\"> \r\n\r\n\r\n\r\n\r\n<p> \r\n\r\n <h1>Copyright and Licensing</h1>\r\n    <p><strong>Tethys Environmental Science</strong> is committed to open access and the transparency of copyright and licensing practices.</p>\r\n\r\n    <p>This <strong>Copyright License Agreement</strong> confirms that:</p>\r\n    <ul>\r\n        <li>The <strong>authors retain the copyright</strong> of their articles.</li>\r\n        <li>The <strong>publisher holds a non-exclusive license</strong> to publish the articles.</li>\r\n        <li>All articles are published under the terms of the <a href=\"https://creativecommons.org/licenses/by/4.0/\" target=\"_blank\"><strong>Creative Commons Attribution 4.0 International License (CC BY 4.0)</strong></a>.</li>\r\n    </ul>\r\n\r\n    <h2>License Statement</h2>\r\n    <p>This Copyright License Agreement is made to confirm that the authors retain the copyright of their article and grant the publisher a non-exclusive license to publish the article under the terms of the <strong>Creative Commons Attribution 4.0 International License (CC BY 4.0)</strong>.</p>\r\n\r\n    <p>The author(s) agree to publish the article under the Creative Commons Attribution 4.0 International License (CC BY 4.0), which allows others to <strong>share, copy, distribute, adapt, and build upon the work for any purpose</strong>, even commercially, <strong>provided appropriate credit is given</strong>.</p>\r\n\r\n    <p>The authors <strong>retain copyright</strong> and grant the publisher a <strong>non-exclusive license to publish</strong> the work.</p>\r\n\r\n    <h2>Key Points</h2>\r\n    <ul>\r\n        <li>✅ Articles are published under <strong>CC BY 4.0</strong>.</li>\r\n        <li>✅ Authors <strong>retain copyright</strong>.</li>\r\n        <li>✅ The publisher is granted a <strong>non-exclusive publishing license</strong>.</li>\r\n    </ul>\r\n\r\n<br /> </p></div></div></div><hr /> \r\n\r\n',1,'2024-03-20 19:38:04');
